package com.example.myapp;

import com.getcapacitor.JSObject;
import com.getcapacitor.Plugin;
import com.getcapacitor.PluginCall;
import com.getcapacitor.PluginMethod;
import com.getcapacitor.annotation.CapacitorPlugin;

@CapacitorPlugin(name = "Counter")
public class CounterPlugin extends Plugin {

    private int counter = 0;

    @PluginMethod
    public void increment(PluginCall call) {
        counter++;
        JSObject ret = new JSObject();
        ret.put("value", counter);
        notifyListeners("change", ret);
        call.resolve(ret);
    }

    @PluginMethod
    public void reset(PluginCall call) {
        counter = 0;
        JSObject ret = new JSObject();
        ret.put("value", counter);
        notifyListeners("change", ret);
        call.resolve(ret);
    }

    @PluginMethod
    public void getValue(PluginCall call) {
        JSObject ret = new JSObject();
        ret.put("value", counter);
        call.resolve(ret);
    }
}

package com.example.myapp;

import android.os.Bundle;
import com.getcapacitor.BridgeActivity;

public class MainActivity extends BridgeActivity {
    @Override
    public void onCreate(Bundle savedInstanceState) {
        registerPlugin(CounterPlugin.class);
        super.onCreate(savedInstanceState);
    }
}

