import { registerPlugin, PluginListenerHandle } from '@capacitor/core';

export interface CounterPlugin {
  increment(): Promise<{ value: number }>;
  reset(): Promise<{ value: number }>;
  getValue(): Promise<{ value: number }>;
  addListener(
    eventName: 'change',
    listenerFunc: (state: { value: number }) => void
  ): Promise<PluginListenerHandle> & PluginListenerHandle;
}

const Counter = registerPlugin<CounterPlugin>('Counter');

export default Counter;

import Counter from './counter';

async function run() {
  const handle = await Counter.addListener('change', (state) => {
    console.log('Counter changed to:', state.value);
  });

  await Counter.increment();
  await Counter.increment();
  await Counter.reset();
  const val = await Counter.getValue();
  console.log('Final value:', val.value);

  await handle.remove();
}

run();

